import { createClient } from '@supabase/supabase-js'
import { NextResponse } from 'next/server'
export const dynamic = 'force-dynamic'
const COVER_B64 = ``
const CONTENT = `
<p>Receber pedidos por um aplicativo de delivery parece prático, e em parte é. O problema aparece no fim do mês, quando você soma quanto a comissão de cada pedido levou do seu faturamento. Para muitos donos de lanchonete, pizzaria e hamburgueria, essa conta dói mais do que deveria.</p>
<p>A boa notícia é que existe um caminho que coloca esse dinheiro de volta no seu caixa: o cardápio digital próprio, com o pedido chegando direto no seu WhatsApp. Veja as principais vantagens de usar um cardápio digital no lugar de depender só do iFood.</p>

<h2>1. Você para de pagar comissão por pedido</h2>
<p>Essa é a vantagem mais óbvia e a que mais pesa no bolso. Nos marketplaces de delivery, uma fatia de cada venda fica com a plataforma. No cardápio digital próprio, o pedido vai direto para o seu WhatsApp e a venda é 100% sua. Em um mês movimentado, o que você economiza em comissão pode pagar várias outras contas do negócio.</p>

<h2>2. O cliente passa a ser seu, não da plataforma</h2>
<p>Dentro do aplicativo de delivery, o cliente é da plataforma. Você não tem o contato, não consegue avisar de uma promoção e não constrói relacionamento. Com o cardápio digital, o pedido chega pelo seu WhatsApp e você passa a ter um canal direto para fidelizar, avisar de novidades e trazer o cliente de volta.</p>

<h2>3. Você controla os preços sem repassar taxa</h2>
<p>Quem vende por marketplace muitas vezes precisa aumentar os preços para compensar a comissão. No canal próprio, você define o preço justo, pode até oferecer um valor melhor que no aplicativo e ainda assim lucrar mais por pedido.</p>

<h2>4. Cupons e fidelidade que trabalham a seu favor</h2>
<p>No Cardápio Turbo você cria cupons de desconto e um programa de fidelidade (por exemplo, a cada 10 pedidos, 1 grátis). São ferramentas que aumentam a recorrência e premiam quem compra direto com você, algo difícil de fazer dentro de um marketplace fechado.</p>

<h2>5. Seu cardápio com a cara da sua marca</h2>
<p>No aplicativo de delivery, sua loja fica padronizada como todas as outras. No cardápio digital próprio, você personaliza cores, logo e tema. O cliente vê um cardápio profissional, com a identidade do seu negócio, o que passa mais confiança e valoriza a marca.</p>

<h2>6. Pedido organizado e sem erro de anotação</h2>
<p>O pedido chega no seu WhatsApp já formatado, com itens, observações, forma de pagamento, endereço e valor total. Some isso ao painel de pedidos ao vivo e ao frete automático por bairro, e você ganha organização sem depender da estrutura de terceiros.</p>

<h2>7. Dados e relatórios que são seus</h2>
<p>Com o cardápio digital, você acompanha os produtos mais vendidos, as visualizações e o desempenho do cardápio. Essas informações ajudam a decidir o que destacar, quais fotos melhorar e quais combos criar. No marketplace, esses dados ficam com a plataforma.</p>

<h2>iFood e cardápio digital podem conviver</h2>
<p>Importante: não se trata de abandonar o iFood do dia para a noite. O marketplace ajuda a ser descoberto por novos clientes. A estratégia inteligente é usar o aplicativo para aquisição e o cardápio digital próprio para reter o cliente que já te conhece, sem comissão. Quem já pede de você é incentivado a pedir direto, por exemplo com um cupom exclusivo no canal próprio.</p>
<p>Para isso funcionar dentro das regras, o convite para pedir direto deve acontecer fora da plataforma de delivery: na loja física, na embalagem de pedidos próprios, no Instagram e no status do WhatsApp. Assim você reduz custo sem se expor a punição.</p>

<h2>Como começar com o seu cardápio digital</h2>
<p>Montar o seu leva cerca de 10 minutos e não exige programador. Você cadastra os produtos com foto e preço, personaliza com a sua marca, gera o QR Code e o link e já começa a receber pedidos no WhatsApp. Coloque o QR Code na mesa, no balcão e na embalagem, e divulgue o link nas redes.</p>
<p><a href="https://cardapioturbo.com.br/register"><strong>Crie seu cardápio digital grátis no Cardápio Turbo</strong></a> e teste por 7 dias, sem cartão de crédito. Comece a vender direto, pagar menos comissão e construir uma base de clientes que é realmente sua.</p>
`
export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!)
  const slug = 'cardapio-digital-vs-ifood'
  const buffer = Buffer.from(COVER_B64, 'base64')
  const path = `${slug}.png`
  await supabase.storage.from('blog').upload(path, buffer, { contentType: 'image/png', upsert: true })
  const coverUrl = supabase.storage.from('blog').getPublicUrl(path).data.publicUrl
  await supabase.from('blog_posts').delete().eq('slug', slug)
  const { data, error } = await supabase.from('blog_posts').insert({
    title: 'Cardápio digital ou iFood? 7 vantagens de receber o pedido direto no seu WhatsApp',
    slug,
    excerpt: 'A comissão de cada pedido pesa mais do que parece. Veja 7 vantagens de usar um cardápio digital próprio no lugar de depender só do iFood, sem abandonar o marketplace.',
    content: CONTENT,
    category: 'Guias',
    author: 'Equipe Cardápio Turbo',
    cover_emoji: '⚖️',
    cover_image: coverUrl,
    read_minutes: 7,
    seo_title: 'Cardápio digital x iFood: 7 vantagens de vender direto no WhatsApp',
    seo_description: 'Pare de pagar comissão por pedido. Conheça as vantagens de um cardápio digital próprio frente ao iFood e como usar os dois juntos a seu favor.',
    keywords: 'cardápio digital, cardápio digital ou ifood, comissão ifood, vender direto whatsapp, alternativa ifood, cardápio próprio',
    published: true,
    published_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  }).select('slug').single()
  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json({ ok: true, slug: data.slug, coverUrl })
}
